  ('elementary-e3452428-moex-00177', 'elementary-e3452428', 'elementary-e3452428-moex-114-55d283b0', 'sub-elementary-e3452428-04', NULL, 'single_choice', '下列何者非民法之債務不履行責任？', '["給付不能損害賠償責任", "給付遲延損害賠償責任", "不當得利返還責任", "不完全給付損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00178', 'elementary-e3452428', 'elementary-e3452428-moex-114-55d283b0', 'sub-elementary-e3452428-04', NULL, 'single_choice', '甲委請乙律師擔任訴訟代理人，到法院進行訴訟，就甲與乙間之法律關係，下列敘述何者正確？', '["委任", "僱傭", "承攬", "居間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00179', 'elementary-e3452428', 'elementary-e3452428-moex-114-55d283b0', 'sub-elementary-e3452428-04', NULL, 'single_choice', '甲將A屋出租給乙並交付，乙合法轉租給丙並交付，下列敘述何者正確？', '["甲得請求乙返還A屋", "甲不得請求丙返還A屋", "甲得請求丙支付A屋租金", "甲得向乙請求丙支付之租金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00180', 'elementary-e3452428', 'elementary-e3452428-moex-114-55d283b0', 'sub-elementary-e3452428-04', NULL, 'single_choice', '關於收養之效力，下列敘述何者正確？', '["養子女對本生父母，仍享有法定繼承權", "養父母均死亡時，應為未成年之養子女置監護人", "繼親收養者，養子女與本生父母之權利義務關係均停止", "本生父母若有受扶養之必要時，得向其已被出養之子女，請求給付扶養費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
  ('elementary-e3452428-moex-00181', 'elementary-e3452428', 'elementary-e3452428-moex-114-55d283b0', 'sub-elementary-e3452428-04', NULL, 'single_choice', '關於親屬間之扶養義務與權利，下列敘述何者正確？', '["夫妻互負扶養義務，其負扶養義務之順序與直系血親卑親屬同，其受扶養權利之順序與直系血親尊親屬同", "父母離婚後，未行使親權之一方，對未成年子女無須負扶養義務", "扶養之方法與給付費用，由當事人協議定之，不能協議時，專屬親屬會議或法定監護人定之", "受扶養權利人為直系血親尊親屬時，如其不能維持生活，且無謀生能力，並未領取重大傷病卡者，扶養 義務人不得減輕或免除其扶養義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:04+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "502", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般民政"}'::jsonb, NULL),
